// Recebe payload do Hubtrix: { texto, mensagem_id, tenant_slug, lead_id }
const body = items[0].json.body || items[0].json;
const texto = (body.texto || '').toString();

if (!texto.trim()) {
  return [{json: {erro: 'texto vazio', sugestoes: []}}];
}

const systemPrompt = `Voce e um extrator de dados de cadastro a partir de mensagens curtas de WhatsApp/chat brasileiro. Sua tarefa: identificar quais campos do CATALOGO estao presentes no TEXTO e extrair o valor normalizado.

CATALOGO DE CAMPOS DISPONIVEIS:
- nome_razaosocial: nome completo do titular (pessoa fisica ou razao social)
- cpf_cnpj: 11 digitos (CPF) ou 14 (CNPJ); pode vir com mascara
- email: endereco de e-mail
- data_nascimento: formato ISO YYYY-MM-DD (converta o que vier)
- rg: documento RG (numeros + letra)
- cep: 8 digitos brasileiros (pode vir com hifen)
- cidade: nome da cidade
- estado: UF (2 letras maiusculas)

REGRAS OBRIGATORIAS:
1. So extraia campos que tenham EVIDENCIA DIRETA no texto. NUNCA invente.
2. Para cada campo, devolva o trecho ORIGINAL do texto ("trecho_origem") que originou a extracao.
3. O trecho_origem DEVE aparecer literalmente no texto (case-insensitive).
4. Confianca 0.0 a 1.0:
   - 0.95+ quando inequivoco (ex: CPF formato 000.000.000-00)
   - 0.7-0.9 quando provavel por contexto/posicao
   - Abaixo de 0.7 NAO inclua
5. Normalize: nome em Title Case; CPF so digitos; data em ISO; UF maiuscula; CEP so digitos.
6. Em caso de duvida, OMITA o campo. Falso negativo e melhor que falso positivo.

TEXTO:
"""
${texto}
"""

Responda EXCLUSIVAMENTE com JSON valido no formato:
{"sugestoes": [{"campo": "...", "valor": "...", "trecho_origem": "...", "confianca": 0.95}]}`;

return [{json: {
  texto,
  mensagem_id: body.mensagem_id,
  tenant_slug: body.tenant_slug,
  lead_id: body.lead_id,
  system_prompt: systemPrompt,
}}];

// Valida saida da OpenAI: parseia JSON, checa trecho_origem in texto, regex/checksum por campo
const ctx = $('Monta Prompt').first().json;
const texto = (ctx.texto || '').toLowerCase();

let sugestoesBrutas = [];
try {
  const content = items[0].json.choices?.[0]?.message?.content || '{}';
  const parsed = JSON.parse(content);
  sugestoesBrutas = parsed.sugestoes || [];
} catch (e) {
  return [{json: {erro: 'falha parse openai', detalhe: String(e), sugestoes: []}}];
}

function cpfValido(raw) {
  const cpf = String(raw).replace(/\D/g, '');
  if (cpf.length !== 11 || /^(\d)\1+$/.test(cpf)) return false;
  let soma = 0;
  for (let i = 0; i < 9; i++) soma += parseInt(cpf[i]) * (10 - i);
  let d1 = 11 - (soma % 11); if (d1 > 9) d1 = 0;
  if (d1 !== parseInt(cpf[9])) return false;
  soma = 0;
  for (let i = 0; i < 10; i++) soma += parseInt(cpf[i]) * (11 - i);
  let d2 = 11 - (soma % 11); if (d2 > 9) d2 = 0;
  return d2 === parseInt(cpf[10]);
}

const REGEX = {
  email: /^[\w.+-]+@[\w-]+\.[\w.-]+$/,
  cep: /^\d{8}$/,
  data_nascimento: /^\d{4}-\d{2}-\d{2}$/,
  estado: /^[A-Z]{2}$/,
};

const CAMPOS_PERMITIDOS = new Set(['nome_razaosocial','cpf_cnpj','email','data_nascimento','rg','cep','cidade','estado']);

const validadas = [];
const rejeitadas = [];

for (const s of sugestoesBrutas) {
  const motivos = [];
  if (!s.campo || !CAMPOS_PERMITIDOS.has(s.campo)) motivos.push('campo invalido');
  if (!s.trecho_origem) motivos.push('sem trecho_origem');
  if (!s.valor) motivos.push('sem valor');
  if (typeof s.confianca !== 'number' || s.confianca < 0.7) motivos.push('confianca <0.7');
  if (s.trecho_origem && !texto.includes(String(s.trecho_origem).toLowerCase())) motivos.push('trecho nao bate no texto');

  if (motivos.length === 0) {
    let valorNorm = s.valor;
    if (s.campo === 'cpf_cnpj') {
      const limpo = String(valorNorm).replace(/\D/g, '');
      if (limpo.length === 11) {
        if (!cpfValido(limpo)) { motivos.push('cpf checksum'); }
        else valorNorm = limpo;
      } else if (limpo.length === 14) {
        valorNorm = limpo;
      } else {
        motivos.push('cpf/cnpj tamanho');
      }
    } else if (s.campo === 'cep') {
      const limpo = String(valorNorm).replace(/\D/g, '');
      if (limpo.length !== 8) motivos.push('cep tamanho');
      else valorNorm = limpo;
    } else if (REGEX[s.campo]) {
      const ok = REGEX[s.campo].test(String(valorNorm));
      if (!ok) motivos.push(`regex ${s.campo}`);
    } else {
      if (String(valorNorm).trim().length < 2) motivos.push('valor curto');
    }
    if (motivos.length === 0) {
      validadas.push({campo: s.campo, valor: valorNorm, trecho_origem: s.trecho_origem, confianca: s.confianca});
      continue;
    }
  }
  rejeitadas.push({...s, motivos});
}

return [{json: {
  sugestoes: validadas,
  total_brutas: sugestoesBrutas.length,
  total_validadas: validadas.length,
  rejeitadas,
  contexto: {mensagem_id: ctx.mensagem_id, lead_id: ctx.lead_id, tenant_slug: ctx.tenant_slug}
}}];
